    std::priority_queue<int, std::vector<int>, std::greater<int>> pq;
public:
    SeatManager(int n) {
        for (int i = 1; i <= n; ++i) pq.push(i);
    }

    int reserve() {
        int seat = pq.top();
        pq.pop();
        return seat;
    }

    void unreserve(int seatNumber) {
        pq.push(seatNumber);
    }
};
